@props(['estados','cidadesPorEstado'])@php $estadosArray=[];if(isset($estados)){foreach($estados as $sigla=>$nome){$estadosArray[]=['id'=>$sigla,'texto'=>$nome];}}@endphp<div class="mb-8 border-b border-white/10 pb-8" x-data="{estados:@js($estadosArray),cidadesPorEstado:@js($cidadesPorEstado),cidadesDisponiveis:[],ufId:'{{ request('uf') }}',ufTexto:'',ufAberto:false,cidadeId:'{{ request('cidade') }}',cidadeTexto:'',cidadeAberto:false,init(){if(this.ufId){let est=this.estados.find(e=>e.id===this.ufId);if(est){this.ufTexto=est.texto;let cidadeAtual=this.cidadeId;this.atualizarCidades(this.ufId);if(cidadeAtual&&this.cidadesDisponiveis.length>0){let cid=this.cidadesDisponiveis.find(c=>String(c.codigo)===String(cidadeAtual));if(cid){this.cidadeId=cidadeAtual;this.cidadeTexto=cid.nome;}}}}},get estadosFiltrados(){if(this.ufTexto==='')return this.estados;return this.estados.filter(e=>e.texto.toLowerCase().includes(this.ufTexto.toLowerCase()));},get cidadesFiltradas(){if(this.cidadeTexto==='')return this.cidadesDisponiveis;return this.cidadesDisponiveis.filter(c=>c.nome.toLowerCase().includes(this.cidadeTexto.toLowerCase()));},selecionarEstado(estado){this.ufId=estado.id;this.ufTexto=estado.texto;this.ufAberto=false;this.atualizarCidades(estado.id);},limparEstado(){this.ufId='';this.ufTexto='';this.cidadesDisponiveis=[];this.limparCidade();},atualizarCidades(uf){this.limparCidade();if(uf&&this.cidadesPorEstado[uf]){this.cidadesDisponiveis=this.cidadesPorEstado[uf];}else{this.cidadesDisponiveis=[];}},selecionarCidade(cidade){this.cidadeId=cidade.codigo;this.cidadeTexto=cidade.nome;this.cidadeAberto=false;},limparCidade(){this.cidadeId='';this.cidadeTexto='';this.cidadeAberto=false;}}"><h3 class="text-white font-bold text-lg flex items-center gap-2 mb-6"><i class="bi bi-geo-alt-fill text-amber-500"></i>Localização</h3><div class="grid grid-cols-1 md:grid-cols-12 gap-6"><div class="md:col-span-6 relative" @click.outside="ufAberto=false"><label class="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Estado (UF)</label><div class="relative"><input type="text" x-model="ufTexto" @focus="ufAberto=true" @input="ufAberto=true;ufId=''" placeholder="Selecione o Estado..." class="w-full bg-[#050509] border border-white/10 text-white rounded-xl py-3 pl-4 pr-10 focus:ring-2 focus:ring-amber-500/50 focus:border-amber-500 outline-none transition-all placeholder-gray-600 autocomplete-off"><input type="hidden" name="uf" :value="ufId"><div class="absolute inset-y-0 right-0 flex items-center px-4 cursor-pointer"><template x-if="ufTexto"><i class="bi bi-x text-gray-500 hover:text-red-500 transition-colors" @click="limparEstado()"></i></template><template x-if="!ufTexto"><i class="bi bi-chevron-down text-gray-500 transition-transform" :class="ufAberto?'rotate-180':''" @click="ufAberto=!ufAberto"></i></template></div><div x-show="ufAberto" class="absolute z-50 w-full mt-2 bg-[#1A1A1E] border border-white/10 rounded-xl shadow-2xl max-h-60 overflow-y-auto" style="display:none;" x-transition:enter="transition ease-out duration-100" x-transition:enter-start="opacity-0 scale-95" x-transition:enter-end="opacity-100 scale-100"><ul><template x-for="estado in estadosFiltrados" :key="estado.id"><li @click="selecionarEstado(estado)" class="px-4 py-3 hover:bg-white/5 hover:text-amber-400 cursor-pointer text-sm text-gray-300 border-b border-white/5 last:border-0 transition-colors"><span x-text="estado.texto"></span>(<span x-text="estado.id" class="font-mono text-xs text-gray-500"></span>)</li></template><li x-show="estadosFiltrados.length===0" class="px-4 py-3 text-sm text-gray-500 text-center">Nenhum estado encontrado.</li></ul></div></div></div><div class="md:col-span-6 relative" @click.outside="cidadeAberto=false"><label class="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Cidade</label><div class="relative"><input type="text" x-model="cidadeTexto" @focus="cidadeAberto=true" @input="cidadeAberto=true;cidadeId=''" placeholder="Selecione a Cidade..." :disabled="!ufId" :class="!ufId?'bg-[#050509]/50 text-gray-600 cursor-not-allowed border-white/5':'bg-[#050509] text-white cursor-text focus:ring-2 focus:ring-amber-500/50 focus:border-amber-500 border-white/10'" class="w-full border rounded-xl py-3 pl-4 pr-10 outline-none transition-all placeholder-gray-600 autocomplete-off"><input type="hidden" name="cidade" :value="cidadeId"><div class="absolute inset-y-0 right-0 flex items-center px-4 cursor-pointer"><template x-if="cidadeTexto"><i class="bi bi-x text-gray-500 hover:text-red-500 transition-colors" @click="limparCidade()"></i></template><template x-if="!cidadeTexto"><i class="bi bi-chevron-down text-gray-500 transition-transform" :class="cidadeAberto?'rotate-180':''" @click="if(ufId) cidadeAberto=!cidadeAberto"></i></template></div><div x-show="cidadeAberto&&ufId" class="absolute z-50 w-full mt-2 bg-[#1A1A1E] border border-white/10 rounded-xl shadow-2xl max-h-60 overflow-y-auto" style="display:none;" x-transition:enter="transition ease-out duration-100" x-transition:enter-start="opacity-0 scale-95" x-transition:enter-end="opacity-100 scale-100"><ul><template x-for="cidade in cidadesFiltradas" :key="cidade.codigo"><li @click="selecionarCidade(cidade)" class="px-4 py-3 hover:bg-white/5 hover:text-amber-400 cursor-pointer text-sm text-gray-300 border-b border-white/5 last:border-0 transition-colors"><span x-text="cidade.nome"></span></li></template><li x-show="cidadesFiltradas.length===0" class="px-4 py-3 text-sm text-gray-500 text-center">Nenhuma cidade encontrada.</li></ul></div></div><p x-show="!ufId" class="text-[10px] text-gray-500 mt-1.5 ml-1">Selecione um estado primeiro.</p></div></div></div>
